import React, { useEffect, useState } from 'react';
import toast from 'react-hot-toast';
import { phieuTamTruAPI, phongAPI } from '../services/api';

export default function PhieuTamTru() {
  const [phieus, setPhieus] = useState([]);
  const [phongs, setPhongs] = useState([]);
  const [form, setForm] = useState({ maPhong:'', hoTen:'', soDienThoai:'', ngaySinh:'', diaChiThuongTru:'', ngayBatDau:'' });
  const [tab, setTab] = useState('list');
  const [submitting, setSubmitting] = useState(false);
  const set = (k,v) => setForm(f => ({...f, [k]:v}));

  useEffect(() => {
    phieuTamTruAPI.layCuaToi().then(r => setPhieus(r.data.data || []));
    phongAPI.layPhongCuaToi().then(r => setPhongs(r.data.data || []));
  }, []);

  const handleSubmit = async e => {
    e.preventDefault();
    setSubmitting(true);
    try {
      await phieuTamTruAPI.tao({ ...form, maPhong: parseInt(form.maPhong) });
      toast.success('Tạo phiếu tạm trú thành công!');
      phieuTamTruAPI.layCuaToi().then(r => setPhieus(r.data.data || []));
      setTab('list');
    } catch (e) { toast.error(e.response?.data?.message || 'Thất bại'); }
    setSubmitting(false);
  };

  return (
    <div className="container page-wrapper">
      <h1 className="section-title">📄 Phiếu tạm trú</h1>
      <p className="section-subtitle">Tạo và quản lý phiếu đăng ký tạm trú</p>
      <div className="tabs">
        {[['list','📋 Danh sách'], ['new','➕ Tạo phiếu mới']].map(([k,l]) => (
          <div key={k} className={`tab ${tab===k?'active':''}`} onClick={() => setTab(k)}>{l}</div>
        ))}
      </div>

      {tab === 'list' && (
        phieus.length === 0
          ? <div className="empty-state"><div className="empty-state-icon">📄</div><p>Chưa có phiếu tạm trú nào.</p></div>
          : <div style={{ display:'flex', flexDirection:'column', gap: 14 }}>
              {phieus.map(p => (
                <div key={p.maPhieuTamTru} className="card">
                  <div className="card-body">
                    <div style={{ display:'flex', justifyContent:'space-between', flexWrap:'wrap', gap: 12 }}>
                      <div>
                        <div style={{ fontWeight: 700, fontSize: 16 }}>#{p.maPhieuTamTru} — {p.hoTen}</div>
                        <div style={{ color:'var(--text-muted)', fontSize: 13, marginTop: 4 }}>
                          🏠 {p.tenPhong} · 📍 {p.diaChiThuongTru}
                        </div>
                        <div style={{ color:'var(--text-muted)', fontSize: 12, marginTop: 4 }}>
                          📅 Bắt đầu: {p.ngayBatDau} · 🎂 {p.ngaySinh}
                        </div>
                      </div>
                      <button className="btn btn-outline btn-sm"
                        onClick={() => {
                          const content = `PHIẾU ĐĂNG KÝ TẠM TRÚ\n\nHọ tên: ${p.hoTen}\nNgày sinh: ${p.ngaySinh}\nĐịa chỉ thường trú: ${p.diaChiThuongTru}\nSố điện thoại: ${p.soDienThoai}\nPhòng: ${p.tenPhong}\nNgày bắt đầu tạm trú: ${p.ngayBatDau}`;
                          const blob = new Blob([content], { type: 'text/plain;charset=utf-8' });
                          const url = URL.createObjectURL(blob);
                          const a = document.createElement('a'); a.href=url; a.download=`phieu-tam-tru-${p.maPhieuTamTru}.txt`; a.click();
                        }}>
                        📥 Tải về
                      </button>
                    </div>
                  </div>
                </div>
              ))}
            </div>
      )}

      {tab === 'new' && (
        <div style={{ maxWidth: 600 }}>
          <div className="card">
            <div className="card-header">📄 Tạo phiếu đăng ký tạm trú</div>
            <div className="card-body">
              <div className="alert alert-info">ℹ️ Thông tin sẽ được điền tự động từ CCCD đã xác thực.</div>
              <form onSubmit={handleSubmit}>
                <div className="form-group">
                  <label className="form-label">Chọn phòng *</label>
                  <select className="form-control" required value={form.maPhong} onChange={e => set('maPhong', e.target.value)}>
                    <option value="">-- Chọn phòng --</option>
                    {phongs.map(p => <option key={p.maPhong} value={p.maPhong}>{p.title}</option>)}
                  </select>
                </div>
                <div className="grid-2">
                  <div className="form-group"><label className="form-label">Họ tên *</label><input className="form-control" required value={form.hoTen} onChange={e => set('hoTen', e.target.value)} /></div>
                  <div className="form-group"><label className="form-label">Số điện thoại</label><input className="form-control" value={form.soDienThoai} onChange={e => set('soDienThoai', e.target.value)} /></div>
                </div>
                <div className="grid-2">
                  <div className="form-group"><label className="form-label">Ngày sinh</label><input className="form-control" type="date" value={form.ngaySinh} onChange={e => set('ngaySinh', e.target.value)} /></div>
                  <div className="form-group"><label className="form-label">Ngày bắt đầu tạm trú *</label><input className="form-control" type="date" required value={form.ngayBatDau} onChange={e => set('ngayBatDau', e.target.value)} /></div>
                </div>
                <div className="form-group"><label className="form-label">Địa chỉ thường trú</label><input className="form-control" value={form.diaChiThuongTru} onChange={e => set('diaChiThuongTru', e.target.value)} /></div>
                <button type="submit" className="btn btn-primary btn-block btn-lg" disabled={submitting}>
                  {submitting ? '⏳...' : '📄 Tạo phiếu tạm trú'}
                </button>
              </form>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
